import (
    "context"
    "database/sql"
    entdb "github.com/openmeterio/openmeter/openmeter/ent/db"
    "github.com/openmeterio/openmeter/pkg/framework/entutils"
    "github.com/openmeterio/openmeter/pkg/framework/transaction"
)

type adapter struct{ db *entdb.Client }

func (a *adapter) Tx(ctx context.Context) (context.Context, transaction.Driver, error) {
    txCtx, cfg, drv, err := a.db.HijackTx(ctx, &sql.TxOptions{})
    if err != nil { return nil, nil, err }
    return txCtx, entutils.NewTxDriver(drv, cfg), nil
}
func (a *adapter) WithTx(ctx context.Context, tx *entutils.TxDriver) *adapter {
    return &adapter{db: entdb.NewTxClientFromRawConfig(ctx, *tx.GetConfig()).Client()}
}
func (a *adapter) Self() *adapter { return a }

func (a *adapter) Create(ctx context.Context, ns, name string) error {
    return entutils.TransactingRepoWithNoValue(ctx, a, func(ctx context.Context, tx *adapter) error {
        return tx.db.Entity.Create().SetNamespace(ns).SetName(name).Exec(ctx)
    })
}

import "github.com/openmeterio/openmeter/pkg/models"

func (s *service) Create(ctx context.Context, input CreateInput) (*Entity, error) {
    if err := input.Validate(); err != nil {
        return nil, err // Validate() returns ValidationIssue via models.NewValidationError
    }
    entity, err := s.adapter.GetByKey(ctx, input.Namespace, input.Key)
    if err == nil {
        return nil, models.NewGenericConflictError(models.NamespacedID{Namespace: input.Namespace})
    }
    if !models.IsGenericNotFoundError(err) {
        return nil, err
    }
    return s.adapter.Create(ctx, input)
}

